import os
import time
from datetime import datetime
from http.server import HTTPServer, BaseHTTPRequestHandler
import json
import threading
from urllib.parse import parse_qs, urlparse

class LoggingServer:
    def __init__(self, log_dir='logs', host='0.0.0.0', port=8080):
        self.log_dir = log_dir
        self.host = host
        self.port = port
        self.lock = threading.Lock()
        
        if not os.path.exists(self.log_dir):
            os.makedirs(self.log_dir)
    
    def write_log(self, service_name, level, message, metadata=None):
        timestamp = datetime.now().strftime('%Y-%m-%d %H:%M:%S.%f')[:-3]
        log_file = os.path.join(self.log_dir, '%s.log' % service_name)
        
        log_entry = '[%s] [%s] %s' % (timestamp, level.upper(), message)
        
        if metadata:
            metadata_str = ' | '.join(['%s=%s' % (k, v) for k, v in metadata.items()])
            log_entry = '%s | %s' % (log_entry, metadata_str)
        
        log_entry = '%s\n' % log_entry
        
        with self.lock:
            with open(log_file, 'a', encoding='utf-8') as f:
                f.write(log_entry)
    
    def get_request_handler(self):
        server_instance = self
        
        class LogRequestHandler(BaseHTTPRequestHandler):
            def log_message(self, format, *args):
                pass
            
            def do_POST(self):
                if self.path == '/log':
                    try:
                        content_length = int(self.headers.get('Content-Length', 0))
                        body = self.rfile.read(content_length).decode('utf-8')
                        
                        data = json.loads(body)
                        
                        service_name = data.get('service', 'unknown')
                        level = data.get('level', 'info')
                        message = data.get('message', '')
                        metadata = data.get('metadata', {})
                        
                        server_instance.write_log(service_name, level, message, metadata)
                        
                        self.send_response(200)
                        self.send_header('Content-Type', 'application/json')
                        self.end_headers()
                        self.wfile.write(json.dumps({'status': 'success'}).encode('utf-8'))
                    
                    except Exception as e:
                        self.send_response(500)
                        self.send_header('Content-Type', 'application/json')
                        self.end_headers()
                        self.wfile.write(json.dumps({'status': 'error', 'message': str(e)}).encode('utf-8'))
                
                else:
                    self.send_response(404)
                    self.end_headers()
            
            def do_GET(self):
                if self.path.startswith('/logs/'):
                    try:
                        parsed = urlparse(self.path)
                        path_parts = parsed.path.split('/')
                        service_name = path_parts[2] if len(path_parts) > 2 else None
                        
                        if service_name:
                            log_file = os.path.join(server_instance.log_dir, '%s.log' % service_name)
                            
                            if os.path.exists(log_file):
                                with open(log_file, 'r', encoding='utf-8') as f:
                                    content = f.read()
                                
                                self.send_response(200)
                                self.send_header('Content-Type', 'text/plain')
                                self.end_headers()
                                self.wfile.write(content.encode('utf-8'))
                            else:
                                self.send_response(404)
                                self.send_header('Content-Type', 'application/json')
                                self.end_headers()
                                self.wfile.write(json.dumps({'status': 'error', 'message': 'Log file not found'}).encode('utf-8'))
                        else:
                            self.send_response(400)
                            self.end_headers()
                    
                    except Exception as e:
                        self.send_response(500)
                        self.send_header('Content-Type', 'application/json')
                        self.end_headers()
                        self.wfile.write(json.dumps({'status': 'error', 'message': str(e)}).encode('utf-8'))
                
                elif self.path == '/health':
                    self.send_response(200)
                    self.send_header('Content-Type', 'application/json')
                    self.end_headers()
                    self.wfile.write(json.dumps({'status': 'healthy'}).encode('utf-8'))
                
                else:
                    self.send_response(404)
                    self.end_headers()
        
        return LogRequestHandler
    
    def start(self):
        handler = self.get_request_handler()
        server = HTTPServer((self.host, self.port), handler)
        print('Logging server started on %s:%d' % (self.host, self.port))
        server.serve_forever()


class LogClient:
    def __init__(self, server_url, service_name):
        self.server_url = server_url
        self.service_name = service_name
    
    def log(self, level, message, **metadata):
        import urllib.request
        
        data = {
            'service': self.service_name,
            'level': level,
            'message': message,
            'metadata': metadata
        }
        
        json_data = json.dumps(data).encode('utf-8')
        
        req = urllib.request.Request(
            '%s/log' % self.server_url,
            data=json_data,
            headers={'Content-Type': 'application/json'}
        )
        
        try:
            with urllib.request.urlopen(req) as response:
                return response.read().decode('utf-8')
        except Exception as e:
            print('Failed to send log: %s' % str(e))
            return None
    
    def debug(self, message, **metadata):
        return self.log('debug', message, **metadata)
    
    def info(self, message, **metadata):
        return self.log('info', message, **metadata)
    
    def warning(self, message, **metadata):
        return self.log('warning', message, **metadata)
    
    def error(self, message, **metadata):
        return self.log('error', message, **metadata)
    
    def critical(self, message, **metadata):
        return self.log('critical', message, **metadata)


